import socket
import struct
import threading
import time
import json
from typing import Dict, List, Tuple

HOST = "0.0.0.0"
PORT = 27015
MAX_DATAGRAM = 65507

SERVER_NAME = "Python UDP Game Server"
GAME_MODE = "deathmatch"
MAP_NAME = "arena"
MAX_PLAYERS = 16

STATE_LOCK = threading.Lock()
START_TIME = time.time()

players: List[Dict] = [
    {"id": 1, "name": "Alice", "score": 12, "ping": 42, "team": "red"},
    {"id": 2, "name": "Bob", "score": 9, "ping": 58, "team": "blue"},
    {"id": 3, "name": "Carol", "score": 15, "ping": 33, "team": "red"},
]

game_state: Dict = {
    "server_name": SERVER_NAME,
    "map": MAP_NAME,
    "mode": GAME_MODE,
    "max_players": MAX_PLAYERS,
    "uptime_seconds": 0,
    "tick_rate": 60,
    "version": "1.0.0",
    "status": "online",
}


def snapshot() -> Dict:
    with STATE_LOCK:
        game_state["uptime_seconds"] = int(time.time() - START_TIME)
        return {
            "game_state": dict(game_state),
            "players": [dict(p) for p in players],
        }


def build_status_response() -> bytes:
    data = snapshot()
    payload = json.dumps(data, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    return payload


def split_chunks(data: bytes, chunk_size: int = 1200) -> List[bytes]:
    if len(data) <= chunk_size:
        return [data]
    chunks = []
    total = (len(data) + chunk_size - 1) // chunk_size
    for i in range(total):
        part = data[i * chunk_size : (i + 1) * chunk_size]
        header = struct.pack("!HH", i, total)
        chunks.append(header + part)
    return chunks


def handle_client(sock: socket.socket, addr: Tuple[str, int], data: bytes) -> None:
    try:
        text = data.decode("utf-8", errors="ignore").strip().lower()
    except Exception:
        text = ""

    if text in ("status", "info", "query", "serverinfo"):
        payload = build_status_response()
        if len(payload) <= MAX_DATAGRAM - 1:
            sock.sendto(payload, addr)
        else:
            for chunk in split_chunks(payload, 1200):
                sock.sendto(chunk, addr)
        return

    if text.startswith("echo "):
        resp = text[5:].encode("utf-8", errors="ignore")
        sock.sendto(resp[:MAX_DATAGRAM], addr)
        return

    help_msg = (
        b"commands: status | info | query | serverinfo | echo <text>\n"
    )
    sock.sendto(help_msg, addr)


def serve() -> None:
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    try:
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_BROADCAST, 1)
    except OSError:
        pass
    sock.bind((HOST, PORT))

    while True:
        try:
            data, addr = sock.recvfrom(65535)
        except KeyboardInterrupt:
            break
        except Exception:
            continue
        threading.Thread(target=handle_client, args=(sock, addr, data), daemon=True).start()


if __name__ == "__main__":
    serve()